class LRUCache:
    def __init__(self, capacity):
        self.cap = capacity; self.mp = collections.OrderedDict()
    def get(self, key):
        if key not in self.mp: return -1
        self.mp.move_to_end(key); return self.mp[key]
    def put(self, key, value):
        if key in self.mp: self.mp.move_to_end(key)
        self.mp[key] = value
        if len(self.mp) > self.cap: self.mp.popitem(last=False)

